class MemoryManager:
    def __init__(self, total_memory):
        self.total_memory = total_memory
        self.free_memory = total_memory
        self.allocated_blocks = {}

    def allocate(self, process_id, size):
        # Check if enough memory available
        if self.free_memory >= size:
            # Find first-fit memory block
            address = self.total_memory - self.free_memory
            self.allocated_blocks[process_id] = {
                'address': address,
                'size': size,
                'status': 'allocated'
            }
            self.free_memory -= size
            return f"Memory allocated: {address} to {address + size}"
        else:
            # Perform swapping or show error
            return "Insufficient memory"

    def deallocate(self, process_id):
        if process_id in self.allocated_blocks:
            size = self.allocated_blocks[process_id]['size']
            del self.allocated_blocks[process_id]
            self.free_memory += size
            return f"Process {process_id} memory freed"
        return "Process not found"

# Usage demonstration
mm = MemoryManager(1000)
print(mm.allocate("P1", 200))  # Allocate 200 bytes
print(mm.allocate("P2", 300))  # Allocate 300 bytes
print(mm.deallocate("P1"))     # Free P1 memory

#include <stdio.h>
#include <stdbool.h>

#define MAX_PROCESSES 5
#define TIME_QUANTUM 4

struct Process {
    int pid;
    int burst_time;
    int remaining_time;
    int waiting_time;
    int turnaround_time;
};

void roundRobinScheduling(struct Process processes[], int n) {
    int time = 0;
    int completed = 0;

    printf("\n=== Round Robin Scheduling (Quantum = %d) ===\n", TIME_QUANTUM);

    while (completed < n) {
        for (int i = 0; i < n; i++) {
            if (processes[i].remaining_time > 0) {
                // Execute process for time quantum or remaining time
                int execute_time = (processes[i].remaining_time >= TIME_QUANTUM) 
                                   ? TIME_QUANTUM : processes[i].remaining_time;

                processes[i].remaining_time -= execute_time;
                time += execute_time;

                printf("Time %d-%d: Process P%d (Remaining: %d)\n", 
                       time-execute_time, time, processes[i].pid, 
                       processes[i].remaining_time);

                // Check if process completed
                if (processes[i].remaining_time == 0) {
                    processes[i].turnaround_time = time;
                    processes[i].waiting_time = time - processes[i].burst_time;
                    completed++;
                }
            }
        }
    }
}

int main() {
    struct Process processes[] = {
        {1, 10, 10, 0, 0},
        {2, 5, 5, 0, 0},
        {3, 8, 8, 0, 0}
    };

    int n = sizeof(processes) / sizeof(processes[0]);

    roundRobinScheduling(processes, n);

    // Calculate average waiting time
    float total_waiting = 0;
    for (int i = 0; i < n; i++) {
        total_waiting += processes[i].waiting_time;
    }

    printf("\nAverage Waiting Time: %.2f\n", total_waiting / n);

    return 0;
}

