BEGIN
  // User requests to read from device (e.g., read from keyboard)

  // Step 1: User program calls read system call
  buffer = READ_FROM_DEVICE(device_id, size)

  // Step 2: OS kernel receives request
  IF NOT user_has_permission(device_id) THEN
    RETURN ERROR_ACCESS_DENIED
  ENDIF

  // Step 3: Device driver prepares device control register
  device_controller = GET_DEVICE_CONTROLLER(device_id)
  device_controller.command_register = READ_COMMAND
  device_controller.address_register = MEMORY_BUFFER_ADDRESS
  device_controller.count_register = size

  // Step 4: Initiate I/O operation
  device_controller.status_register = START_I/O

  // Step 5: CPU can switch to another process (non-blocking)
  // OR wait for interrupt (blocking)

  // Step 6: When I/O complete, device raises interrupt
  INTERRUPT_HANDLER(device_id)
    // Copy data from device buffer to user memory
    COPY_DATA_TO_USER(buffer, user_memory)
    // Wake up waiting process
    UNBLOCK_PROCESS(requesting_process)
  END_INTERRUPT

  RETURN SUCCESS
END
